# --- Destroy a session ---
sub destroy_session {
    my ($session_id) = @_;

    unless (validate_session_id($session_id)) {
        return 0;
    }

    my $filepath = session_filepath($session_id);

    if (-f $filepath && !-l $filepath) {
        unlink($filepath) or warn "Failed to delete session file: $!";
    }

    return 1;
}

# --- Create a new session ---
sub create_session {
    my (%params) = @_;

    my $session_id = generate_session_id();
    my $now = time();

    my $session_data = {
        session_id   => $session_id,
        created_at   => $now,
        last_access  => $now,
        ip_address   => $params{ip_address} || '0.0.0.0',
        user_id      => undef,
        username     => undef,
        email        => undef,
        is_logged_in => '0',
        csrf_token   => generate_session_id(),    # reuse for CSRF token generation
        flash        => {},
        user_data    => {},
    };

    if (save_session($session_id, $session_data)) {
        return ($session_id, $session_data);
    }

    return (undef, undef);
}

# --- Generate session cookie ---
sub make_session_cookie {
    my ($session_id) = @_;

    return CGI::Cookie->new(
        -name     => $COOKIE_NAME,
        -value    => $session_id,
        -path     => '/',
        -httponly  => 1,
        -secure   => 1,
        -samesite => 'Strict',
        -expires  => '+1h',
    );
}

# --- Clean up expired sessions ---
sub cleanup_expired_sessions {
    opendir(my $dh, $SESSION_DIR) or do {
        warn "Cannot open session directory: $!";
        return;
    };

    my $now = time();
    my $cleaned = 0;

    while (my $file = readdir($dh)) {
        next unless $file =~ /\Asess_([a-f0-9]{$SESSION_ID_LEN})\.json\z/;
        my $filepath = File::Spec->catfile($SESSION_DIR, $file);

        # Skip symlinks
        next if -l $filepath;

        my @stat = stat($filepath);
        if (@stat && ($now - $stat[9]) > $SESSION_TIMEOUT) {
            unlink($filepath);
            $cleaned++;
        }
    }

    closedir($dh);
    return $cleaned;
}

# --- Main CGI handler demonstrating session management ---
sub handle_request {
    my $cgi = CGI->new;

    # Retrieve session ID from cookie
    my %cookies = CGI::Cookie->fetch();
    my $session_id;
    my $session_data;

