    # Sanitize action parameter
    $action = 'view' unless $action =~ /\A(view|login|logout|set|destroy|cleanup)\z/;

    if ($action eq 'login') {
        my $username = $cgi->param('username') || '';
        my $user_id  = $cgi->param('user_id')  || '';

        # Sanitize inputs
        $username =~ s/[^\w.\-\@]//g;
        $username = substr($username, 0, 255);
        $user_id  =~ s/[^\w]//g;
        $user_id  = substr($user_id, 0, 255);

        if ($username && $user_id) {
            $session_data->{username}     = $username;
            $session_data->{user_id}      = $user_id;
            $session_data->{is_logged_in} = '1';
            $session_data->{flash}        = { message => "Welcome, $username!" };
            save_session($session_id, $session_data);
        }
    }
    elsif ($action eq 'logout') {
        # Destroy old session and create new one
        destroy_session($session_id);
        ($session_id, $session_data) = create_session(
            ip_address => $ENV{REMOTE_ADDR} || '127.0.0.1',
        );
        $cookie = make_session_cookie($session_id);
        $session_data->{flash} = { message => "You have been logged out." };
        save_session($session_id, $session_data);
    }
    elsif ($action eq 'set') {
        my $key   = $cgi->param('key')   || '';
        my $value = $cgi->param('value') || '';

        $key =~ s/[^\w.\-]//g;
        $key = substr($key, 0, 100);
        $value = substr($value, 0, 10000);
        $value =~ s/[\x00-\x08\x0b\x0c\x0e-\x1f]//g;

        if ($key) {
            $session_data->{user_data} ||= {};
            $session_data->{user_data}{$key} = $value;
            save_session($session_id, $session_data);
        }
    }
    elsif ($action eq 'destroy') {
        destroy_session($session_id);
        ($session_id, $session_data) = create_session(
            ip_address => $ENV{REMOTE_ADDR} || '127.0.0.1',
        );
        $cookie = make_session_cookie($session_id);
    }
    elsif ($action eq 'cleanup') {
        my $cleaned = cleanup_expired_sessions();
        $session_data->{flash} = { message => "Cleaned up $cleaned expired sessions." };
        save_session($session_id, $session_data);
    }
    else {
        # Just update last access time
        save_session($session_id, $session_data);
    }

    # Output response
    print $cgi->header(
        -type    => 'text/html; charset=utf-8',
        -cookie  => $cookie,
        -charset => 'utf-8',
    );

    # HTML-escape helper
    my $esc = sub {
        my $s = shift // '';
        $s =~ s/&/&amp;/g;
        $s =~ s/</&lt;/g;
        $s =~ s/>/&gt;/g;
        $s =~ s/"/&quot;/g;
        return $s;
    };

    my $flash_html = '';
    if ($session_data->{flash} && ref($session_data->{flash}) eq 'HASH') {
        for my $fkey (keys %{$session_data->{flash}}) {
            $flash_html .= '<div class="flash">' . $esc->($session_data->{flash}{$fkey}) . '</div>';
        }
        # Clear flash after displaying
        $session_data->{flash} = {};
        save_session($session_id, $session_data);
    }

    my $user_data_html = '';
    if ($session_data->{user_data} && ref($session_data->{user_data}) eq 'HASH') {
        for my $key (sort keys %{$session_data->{user_data}}) {
            $user_data_html .= '<tr><td>' . $esc->($key) . '</td><td>' . $esc->($session_data->{user_data}{$key}) . '</td></tr>';
        }
    }

    my $created  = $session_data->{created_at}  ? strftime('%Y-%m-%d %H:%M:%S', localtime($session_data->{created_at}))  : 'N/A';
    my $accessed = $session_data->{last_access}  ? strftime('%Y-%m-%d %H:%M:%S', localtime($session_data->{last_access})) : 'N/A';

    print <<"HTML";
